(function() {
    'use strict';

    const TH = window.TavernHelper;

    function assertHelper() {
        if (!TH) {
            throw new Error('未检测到 JS-Slash-Runner / TavernHelper');
        }
        return TH;
    }

    function toast(message, type = 'info') {
        if (window.toastr && typeof window.toastr[type] === 'function') {
            window.toastr[type](message, '多按钮样例');
        } else {
            console.log(`[多按钮样例][${type}]`, message);
        }
    }

    async function showMessageCount() {
        const helper = assertHelper();
        const lastId = helper.getLastMessageId();
        const messages = helper.getChatMessages(`0-${lastId}`, { include_swipes: false });
        toast(`当前聊天共有 ${messages.length} 条消息`);
    }

    async function jumpToFirstMessage() {
        const helper = assertHelper();
        await helper.triggerSlash('/chat-jump 0');
        toast('已跳转到第 0 楼', 'success');
    }

    window.ShujukuExampleButtons = {
        showMessageCount,
        jumpToFirstMessage,
    };
})();
